mapper.select:
select distinct  from tutor_requirement

order by ${orderByClause}
limit ${limitStart}, ${pageSize}

mapper.update:
update tutor_requirement set
    gmt_create = #{gmtCreate,jdbcType=TIMESTAMP}
    gmt_modified = #{gmtModified,jdbcType=TIMESTAMP}
    status_id = #{statusId,jdbcType=TINYINT}
    user_id = #{userId,jdbcType=BIGINT}
    title = #{title,jdbcType=VARCHAR}
    subject_ids = #{subjectIds,jdbcType=VARCHAR}
    grade_id = #{gradeId,jdbcType=BIGINT}
    province_id = #{provinceId,jdbcType=BIGINT}
    city_id = #{cityId,jdbcType=BIGINT}
    district_id = #{districtId,jdbcType=BIGINT}
    address = #{address,jdbcType=VARCHAR}
    tutor_gender = #{tutorGender,jdbcType=TINYINT}
    tutor_type_pref = #{tutorTypePref,jdbcType=VARCHAR}
    budget_min = #{budgetMin,jdbcType=DECIMAL}
    budget_max = #{budgetMax,jdbcType=DECIMAL}
    contact_name = #{contactName,jdbcType=VARCHAR}
    contact_mobile = #{contactMobile,jdbcType=VARCHAR}
    req_status = #{reqStatus,jdbcType=TINYINT}
    audit_remark = #{auditRemark,jdbcType=VARCHAR}
    view_count = #{viewCount,jdbcType=INTEGER}
    application_count = #{applicationCount,jdbcType=INTEGER}        where id = #{id,jdbcType=BIGINT}
